#[derive(Debug, Serialize)]
struct NexusProviderPresenceHeartbeatRequest {
    nostr_pubkey_hex: String,
    session_id: String,
    node_label: Option<String>,
    client_version: Option<String>,
    relay_urls: Vec<String>,
    products: Vec<String>,
    eligible_product_count: u64,
    ready_model: Option<String>,
    runtime_state: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    diagnostic_summaries: Vec<ProviderDiagnosticSummary>,
    hosting_telemetry: ProviderHostingTelemetrySnapshot,
}

#[derive(Debug, Serialize)]
struct NexusProviderPresenceOfflineRequest {
    nostr_pubkey_hex: String,
    session_id: String,
}

#[derive(Debug, Serialize)]
struct NexusProviderPayoutTargetChallengeRequest {
    nostr_pubkey_hex: String,
    session_id: String,
}

#[derive(Debug, Deserialize)]
struct NexusProviderPayoutTargetChallengeResponse {
    challenge: String,
}

#[derive(Debug, Serialize)]
struct NexusProviderPayoutTargetRegistrationRequest {
    nostr_pubkey_hex: String,
    session_id: String,
    spark_address: String,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    bitcoin_address: Option<String>,
    challenge: String,
    challenge_signature_hex: String,
}

async fn report_provider_presence_heartbeat(
    client: &reqwest::Client,
    config_path: &Path,
    config: &PylonConfig,
    identity: &NostrIdentity,
    session_id: &str,
    snapshot: &ProviderPersistedSnapshot,
) -> Result<()> {
    let hosting_telemetry = build_provider_hosting_telemetry(config_path, snapshot);
    let request = NexusProviderPresenceHeartbeatRequest {
        nostr_pubkey_hex: identity.public_key_hex.clone(),
        session_id: session_id.to_string(),
        node_label: Some(config.node_label.clone()),
        client_version: Some(format!("pylon/{}", env!("CARGO_PKG_VERSION"))),
        relay_urls: config.relay_urls.clone(),
        products: eligible_product_ids(snapshot),
        eligible_product_count: snapshot
            .inventory_rows
            .iter()
            .filter(|row| row.eligible)
            .count() as u64,
        ready_model: selected_local_gemma_runtime_model(config, &snapshot.availability.local_gemma),
        runtime_state: snapshot
            .runtime
            .authoritative_status
            .clone()
            .or_else(|| Some(snapshot.runtime.mode.label().to_string())),
        diagnostic_summaries: load_latest_provider_diagnostic_summaries(config_path),
        hosting_telemetry,
    };
    post_nexus_provider_presence(
        client,
        config,
        "/api/provider-presence/heartbeat",
        &request,
        "heartbeat",
    )
    .await?;
    sync_provider_payout_target(client, config_path, config, identity, session_id).await
}

async fn report_provider_presence_offline(
    client: &reqwest::Client,
    config: &PylonConfig,
    identity: &NostrIdentity,
    session_id: &str,
) -> Result<()> {
    let request = NexusProviderPresenceOfflineRequest {
        nostr_pubkey_hex: identity.public_key_hex.clone(),
        session_id: session_id.to_string(),
    };
    post_nexus_provider_presence(
        client,
        config,
        "/api/provider-presence/offline",
        &request,
        "offline",
    )
    .await
}

fn build_provider_hosting_telemetry(
    config_path: &Path,
    snapshot: &ProviderPersistedSnapshot,
) -> ProviderHostingTelemetrySnapshot {
    let host = load_cached_provider_host_telemetry(config_path);
    ProviderHostingTelemetrySnapshot {
        captured_at_unix_ms: host.captured_at_unix_ms,
        runtime: snapshot.runtime.clone(),
        availability: snapshot.availability.clone(),
        inventory_rows: snapshot.inventory_rows.clone(),
        host: Some(host),
    }
}

fn eligible_product_ids(snapshot: &ProviderPersistedSnapshot) -> Vec<String> {
    snapshot
        .inventory_rows
        .iter()
        .filter(|row| row.eligible)
        .map(|row| row.target.product_id().to_string())
        .collect()
}

fn load_cached_provider_host_telemetry(config_path: &Path) -> ProviderHostTelemetrySnapshot {
    let now = Instant::now();
    let cache = PROVIDER_HOST_TELEMETRY_CACHE.get_or_init(|| Mutex::new(None));
    let mut guard = cache.lock().expect("provider host telemetry cache");
    if let Some(entry) = guard.as_ref() {
        let cache_is_fresh = entry.config_path == config_path
            && now.duration_since(entry.refreshed_at)
                < Duration::from_millis(DEFAULT_PROVIDER_HOST_TELEMETRY_REFRESH_INTERVAL_MS);
        if cache_is_fresh {
            return entry.snapshot.clone();
        }
    }
    let snapshot = collect_provider_host_telemetry(config_path);
    *guard = Some(ProviderHostTelemetryCacheEntry {
        config_path: config_path.to_path_buf(),
        refreshed_at: now,
        snapshot: snapshot.clone(),
    });
    snapshot
}

fn collect_provider_host_telemetry(config_path: &Path) -> ProviderHostTelemetrySnapshot {
    let mut system = System::new_with_specifics(
        RefreshKind::nothing()
            .with_cpu(CpuRefreshKind::everything())
            .with_memory(sysinfo::MemoryRefreshKind::everything()),
    );
    let mut disks = Disks::new_with_refreshed_list();
    let mut networks = Networks::new_with_refreshed_list();
    let mut components = Components::new_with_refreshed_list();

    system.refresh_memory();
    system.refresh_cpu_all();
    disks.refresh(false);
    networks.refresh(false);
    components.refresh(false);

    let host_name = normalize_provider_host_optional_string(System::host_name());
    let os_version = normalize_provider_host_optional_string(System::long_os_version());
    let kernel_version =
        normalize_provider_host_optional_string(Some(System::kernel_long_version()));
    let cpu_arch = normalize_provider_host_optional_string(Some(System::cpu_arch()));
    let cpu_brand = system
        .cpus()
        .iter()
        .find_map(|cpu| normalize_provider_host_optional_string(Some(cpu.brand().to_string())));
    let cpu_frequency_mhz = system
        .cpus()
        .first()
        .map(sysinfo::Cpu::frequency)
        .filter(|frequency| *frequency > 0);
    let cpu_usage_percent = (!system.cpus().is_empty()).then(|| system.global_cpu_usage());
    let load = System::load_average();
    let load_average = Some(ProviderHostLoadAverageTelemetry {
        one: load.one,
        five: load.five,
        fifteen: load.fifteen,
    });
    let memory = Some(ProviderHostMemoryTelemetry {
        used_bytes: system.used_memory(),
        available_bytes: system.available_memory(),
        total_bytes: system.total_memory(),
    });
    let swap = Some(ProviderHostSwapTelemetry {
        used_bytes: system.used_swap(),
        free_bytes: system.free_swap(),
        total_bytes: system.total_swap(),
    });
    let (gpus, power) = detect_provider_gpu_and_power_telemetry();

    ProviderHostTelemetrySnapshot {
        captured_at_unix_ms: u64::try_from(now_epoch_ms()).unwrap_or(0),
        host_name,
        os_version,
        kernel_version,
        cpu_arch,
        physical_cpu_count: System::physical_core_count().map(|count| count as u64),
        logical_cpu_count: system.cpus().len() as u64,
        cpu_brand,
        cpu_frequency_mhz,
        cpu_usage_percent,
        load_average,
        memory,
        swap,
        uptime_seconds: Some(System::uptime()),
        gpus,
        disks: collect_provider_disk_telemetry(disks.list(), config_path),
        network_interfaces: collect_provider_network_interface_telemetry(&networks),
        thermal_components: collect_provider_thermal_telemetry(&components),
        power,
    }
}

fn normalize_provider_host_optional_string(value: Option<String>) -> Option<String> {
    value
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn detect_provider_gpu_and_power_telemetry() -> (
    Vec<ProviderHostGpuTelemetry>,
    Option<ProviderHostPowerTelemetry>,
) {
    if cfg!(target_os = "macos") {
        return (
            detect_macos_provider_host_gpus().unwrap_or_default(),
            detect_macos_provider_power_telemetry().ok(),
        );
    }
    match detect_nvidia_provider_host_gpus() {
        Ok((gpus, draw_summary)) => (
            gpus,
            draw_summary.map(|draw_summary| ProviderHostPowerTelemetry {
                source_summary: Some("nvidia_gpu_power_telemetry".to_string()),
                draw_summary: Some(draw_summary),
            }),
        ),
        Err(_) => (Vec::new(), None),
    }
}

fn detect_macos_provider_host_gpus() -> Result<Vec<ProviderHostGpuTelemetry>> {
    let output = StdCommand::new("system_profiler")
        .args(["SPDisplaysDataType", "-json", "-detailLevel", "mini"])
        .output()?;
    if !output.status.success() {
        bail!("system_profiler failed");
    }
    let payload = serde_json::from_slice::<Value>(&output.stdout)?;
    let Some(entries) = payload.get("SPDisplaysDataType").and_then(Value::as_array) else {
        bail!("SPDisplaysDataType missing");
    };

    let mut gpus = entries
        .iter()
        .filter_map(|entry| {
            let model = entry
                .get("sppci_model")
                .or_else(|| entry.get("_name"))
                .and_then(Value::as_str)
                .and_then(|value| {
                    normalize_provider_host_optional_string(Some(value.to_string()))
                })?;
            let vendor = entry
                .get("spdisplays_vendor")
                .and_then(Value::as_str)
                .and_then(|value| normalize_provider_host_optional_string(Some(value.to_string())));
            let memory_total_label = entry
                .get("spdisplays_vram")
                .or_else(|| entry.get("spdisplays_vram_shared"))
                .and_then(Value::as_str)
                .and_then(|value| normalize_provider_host_optional_string(Some(value.to_string())));
            Some(ProviderHostGpuTelemetry {
                model,
                vendor,
                memory_total_label,
                ..ProviderHostGpuTelemetry::default()
            })
        })
        .collect::<Vec<_>>();
    gpus.sort_by(|left, right| left.model.cmp(&right.model));
    Ok(gpus)
}

fn detect_nvidia_provider_host_gpus() -> Result<(Vec<ProviderHostGpuTelemetry>, Option<String>)> {
    let output = StdCommand::new("nvidia-smi")
        .args([
            "--query-gpu=name,memory.free,memory.total,power.draw,power.limit",
            "--format=csv,noheader,nounits",
        ])
        .output()?;
    if !output.status.success() {
        bail!("nvidia-smi unavailable");
    }
    let stdout = String::from_utf8(output.stdout)?;
    let mut gpus = Vec::new();
    let mut power_rows = Vec::new();
    for line in stdout
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
    {
        let columns = line.split(',').map(str::trim).collect::<Vec<_>>();
        let model = columns
            .first()
            .and_then(|value| normalize_provider_host_optional_string(Some((*value).to_string())));
        let Some(model) = model else {
            continue;
        };
        let memory_free_mib = columns.get(1).and_then(|value| value.parse::<u64>().ok());
        let memory_total_mib = columns.get(2).and_then(|value| value.parse::<u64>().ok());
        let power_draw_watts = columns.get(3).and_then(|value| value.parse::<f64>().ok());
        let power_limit_watts = columns.get(4).and_then(|value| value.parse::<f64>().ok());
        if let (Some(draw), Some(limit)) = (power_draw_watts, power_limit_watts) {
            power_rows.push(format!("{model} {draw:.1}W / {limit:.1}W"));
        }
        gpus.push(ProviderHostGpuTelemetry {
            model,
            memory_total_bytes: memory_total_mib.map(|value| value.saturating_mul(1024 * 1024)),
            memory_free_bytes: memory_free_mib.map(|value| value.saturating_mul(1024 * 1024)),
            memory_total_label: memory_total_mib.map(|value| format!("{value} MiB")),
            memory_free_label: memory_free_mib.map(|value| format!("{value} MiB")),
            power_draw_watts,
            power_limit_watts,
            ..ProviderHostGpuTelemetry::default()
        });
    }
    let draw_summary = (!power_rows.is_empty()).then(|| power_rows.join(", "));
    Ok((gpus, draw_summary))
}

fn detect_macos_provider_power_telemetry() -> Result<ProviderHostPowerTelemetry> {
    let output = StdCommand::new("pmset").args(["-g", "batt"]).output()?;
    if !output.status.success() {
        bail!("pmset failed");
    }
    let stdout = String::from_utf8(output.stdout)?;
    let mut lines = stdout
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty());
    let source_line = lines
        .next()
        .ok_or_else(|| anyhow!("pmset source missing"))?;
    let detail_line = lines.next().unwrap_or_default();
    let source_summary = normalize_provider_host_optional_string(Some(
        source_line
            .split('\'')
            .nth(1)
            .unwrap_or(source_line)
            .to_string(),
    ));
    let detail_summary = normalize_provider_host_optional_string(Some(
        detail_line
            .split('\t')
            .nth(1)
            .unwrap_or(detail_line)
            .split(" present:")
            .next()
            .unwrap_or(detail_line)
            .to_string(),
    ));
    Ok(ProviderHostPowerTelemetry {
        source_summary,
        draw_summary: detail_summary,
    })
}

fn collect_provider_disk_telemetry(
    disks: &[sysinfo::Disk],
    config_path: &Path,
) -> Vec<ProviderHostDiskTelemetry> {
    let mut rows = disks
        .iter()
        .map(|disk| {
            let usage = disk.usage();
            ProviderHostDiskTelemetry {
                mount_point: disk.mount_point().display().to_string(),
                name: normalize_provider_host_optional_string(Some(
                    disk.name().to_string_lossy().into_owned(),
                )),
                file_system: normalize_provider_host_optional_string(Some(
                    disk.file_system().to_string_lossy().into_owned(),
                )),
                kind: Some(format!("{:?}", disk.kind()).to_ascii_lowercase()),
                removable: disk.is_removable(),
                available_space_bytes: disk.available_space(),
                total_space_bytes: disk.total_space(),
                read_bytes_delta: usage.read_bytes,
                written_bytes_delta: usage.written_bytes,
                total_read_bytes: usage.total_read_bytes,
                total_written_bytes: usage.total_written_bytes,
                pylon_home_disk: config_path.starts_with(disk.mount_point()),
            }
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        right
            .pylon_home_disk
            .cmp(&left.pylon_home_disk)
            .then_with(|| left.mount_point.cmp(&right.mount_point))
    });
    rows
}

fn collect_provider_network_interface_telemetry(
    networks: &Networks,
) -> Vec<ProviderHostNetworkInterfaceTelemetry> {
    let mut rows = networks
        .iter()
        .filter(|(name, _)| !provider_network_interface_is_ignored(name.as_str()))
        .map(|(name, network)| ProviderHostNetworkInterfaceTelemetry {
            name: name.to_string(),
            received_bytes_delta: network.received(),
            transmitted_bytes_delta: network.transmitted(),
            total_received_bytes: network.total_received(),
            total_transmitted_bytes: network.total_transmitted(),
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| left.name.cmp(&right.name));
    rows
}

fn provider_network_interface_is_ignored(name: &str) -> bool {
    let normalized = name.trim().to_ascii_lowercase();
    normalized.starts_with("lo")
}

fn collect_provider_thermal_telemetry(
    components: &Components,
) -> Vec<ProviderHostThermalComponentTelemetry> {
    let mut rows = components
        .iter()
        .filter_map(|component| {
            component.temperature().map(|temperature_celsius| {
                ProviderHostThermalComponentTelemetry {
                    label: component.label().to_string(),
                    temperature_celsius,
                    max_celsius: component.max(),
                    critical_celsius: component.critical(),
                }
            })
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| left.label.cmp(&right.label));
    rows
}

async fn post_nexus_provider_presence<T: Serialize>(
    client: &reqwest::Client,
    config: &PylonConfig,
    path: &str,
    payload: &T,
    action: &str,
) -> Result<()> {
    let url = nexus_control_url(config, path);
    let response = client
        .post(url.as_str())
        .json(payload)
        .send()
        .await
        .with_context(|| format!("failed to post pylon provider presence {action} to {url}"))?;
    if !response.status().is_success() {
        let detail = response
            .text()
            .await
            .unwrap_or_else(|_| "failed to decode nexus provider presence error".to_string());
        bail!("nexus provider presence {action} failed: {detail}");
    }
    Ok(())
}

async fn post_nexus_json<T: Serialize, R: DeserializeOwned>(
    client: &reqwest::Client,
    config: &PylonConfig,
    path: &str,
    payload: &T,
    action: &str,
) -> Result<R> {
    let url = nexus_control_url(config, path);
    let response = client
        .post(url.as_str())
        .json(payload)
        .send()
        .await
        .with_context(|| format!("failed to post pylon {action} to {url}"))?;
    if !response.status().is_success() {
        let detail = response
            .text()
            .await
            .unwrap_or_else(|_| format!("failed to decode nexus {action} error"));
        bail!("nexus {action} failed: {detail}");
    }
    response
        .json::<R>()
        .await
        .with_context(|| format!("failed to decode nexus {action} response"))
}

fn provider_payout_target_sync_interval() -> Duration {
    Duration::from_millis(DEFAULT_PROVIDER_PAYOUT_TARGET_SYNC_INTERVAL_MS)
}

async fn sync_provider_payout_target(
    client: &reqwest::Client,
    config_path: &Path,
    config: &PylonConfig,
    identity: &NostrIdentity,
    session_id: &str,
) -> Result<()> {
    let address_report = create_wallet_address_report(config_path).await?;
    sync_provider_payout_target_with_report(client, config, identity, session_id, &address_report)
        .await
}

async fn sync_provider_payout_target_with_report(
    client: &reqwest::Client,
    config: &PylonConfig,
    identity: &NostrIdentity,
    session_id: &str,
    address_report: &WalletAddressReport,
) -> Result<()> {
    let challenge = post_nexus_json::<_, NexusProviderPayoutTargetChallengeResponse>(
        client,
        config,
        "/api/provider-payout-target/challenge",
        &NexusProviderPayoutTargetChallengeRequest {
            nostr_pubkey_hex: identity.public_key_hex.clone(),
            session_id: session_id.to_string(),
        },
        "payout-target challenge",
    )
    .await?;
    let challenge_signature_hex = sign_provider_payout_target_registration(
        identity.private_key_hex.as_str(),
        identity.public_key_hex.as_str(),
        session_id,
        challenge.challenge.as_str(),
        address_report.spark_address.as_str(),
    )
    .map_err(anyhow::Error::msg)?;
    let _: Value = post_nexus_json(
        client,
        config,
        "/api/provider-payout-target/register",
        &NexusProviderPayoutTargetRegistrationRequest {
            nostr_pubkey_hex: identity.public_key_hex.clone(),
            session_id: session_id.to_string(),
            spark_address: address_report.spark_address.clone(),
            bitcoin_address: Some(address_report.bitcoin_address.clone()),
            challenge: challenge.challenge,
            challenge_signature_hex,
        },
        "payout-target register",
    )
    .await?;
    Ok(())
}

fn provider_presence_client() -> Result<reqwest::Client> {
    reqwest::Client::builder()
        .timeout(Duration::from_secs(2))
        .build()
        .context("failed to build pylon provider-presence client")
}

fn openagents_account_link_client() -> Result<reqwest::Client> {
    reqwest::Client::builder()
        .timeout(Duration::from_secs(10))
        .build()
        .context("failed to build OpenAgents account-link client")
}

fn nexus_control_url(config: &PylonConfig, path: &str) -> String {
    format!(
        "{}/{}",
        config.nexus_control_base_url.trim_end_matches('/'),
        path.trim_start_matches('/')
    )
}

fn openagents_account_link_url(base_url: &str) -> Result<reqwest::Url> {
    let parsed = reqwest::Url::parse(base_url)
        .with_context(|| format!("invalid OpenAgents base URL: {base_url}"))?;
    parsed.join("/api/pylon-links/complete").with_context(|| {
        format!("failed to build OpenAgents account-link endpoint from {base_url}")
    })
}

fn decode_private_key_hex(private_key_hex: &str) -> Result<[u8; 32]> {
    let key_bytes = hex::decode(private_key_hex.trim())
        .with_context(|| format!("invalid identity private_key_hex: {private_key_hex}"))?;
    let key_length = key_bytes.len();
    key_bytes.try_into().map_err(|_| {
        anyhow!(
            "invalid identity private_key_hex length {}, expected 32 bytes",
            key_length
        )
    })
}

fn build_openagents_account_link_request(
    config: &PylonConfig,
    identity: &NostrIdentity,
    status: &ProviderStatusResponse,
    token: &str,
) -> OpenAgentsPylonLinkCompletionRequest {
    let (ready_model, products) = status
        .snapshot
        .as_ref()
        .map(|snapshot| {
            (
                selected_local_gemma_runtime_model(config, &snapshot.availability.local_gemma),
                eligible_product_ids(snapshot),
            )
        })
        .unwrap_or_else(|| (None, Vec::new()));

    OpenAgentsPylonLinkCompletionRequest {
        token: token.to_string(),
        public_key_hex: identity.public_key_hex.clone(),
        npub: identity.npub.clone(),
        node_label: Some(config.node_label.clone()),
        runtime_state: Some(provider_runtime_state_label(status)),
        ready_model,
        eligible_product_count: products.len() as u64,
        products,
    }
}

fn build_openagents_account_link_body(
    payload: &OpenAgentsPylonLinkCompletionRequest,
) -> Result<Vec<u8>> {
    serde_json::to_vec(payload).context("failed to serialize Pylon account-link payload")
}

fn build_openagents_account_link_proof(
    identity: &NostrIdentity,
    url: &reqwest::Url,
    body: &[u8],
) -> Result<OpenAgentsAccountLinkProof> {
    let payload_hash = hash_payload(body);
    let auth = HttpAuth::new(url.as_str().to_string(), HttpMethod::Post)
        .with_payload_hash(payload_hash.clone());
    let secret_key = decode_private_key_hex(identity.private_key_hex.as_str())?;
    let created_at = nostr::nip01::unix_now_secs().map_err(anyhow::Error::msg)?;
    let event =
        create_http_auth_event(&auth, &secret_key, created_at).map_err(anyhow::Error::msg)?;
    let event_json = serde_json::to_string(&event)
        .context("failed to serialize Pylon account-link proof event")?;
    let authorization_header =
        encode_authorization_header(event_json.as_str()).map_err(anyhow::Error::msg)?;

    Ok(OpenAgentsAccountLinkProof {
        authorization_header,
        event_id: event.id,
        payload_hash,
        created_at,
    })
}

fn build_account_link_report(
    base_url: &str,
    response: OpenAgentsPylonLinkCompletionResponse,
    proof: &OpenAgentsAccountLinkProof,
) -> AccountLinkReport {
    let OpenAgentsPylonLinkCompletionResponse {
        linked,
        observed_pylon,
        account_link,
    } = response;
    let products = observed_pylon.products;
    AccountLinkReport {
        linked,
        base_url: base_url.trim_end_matches('/').to_string(),
        identity_key: observed_pylon.identity_key,
        public_key_hex: observed_pylon.public_key_hex,
        npub: observed_pylon.npub,
        node_label: observed_pylon
            .node_label
            .unwrap_or_else(|| "pylon".to_string()),
        runtime_state: observed_pylon
            .runtime_state
            .unwrap_or_else(|| "unknown".to_string()),
        ready_model: observed_pylon.ready_model,
        eligible_product_count: observed_pylon
            .eligible_product_count
            .unwrap_or(products.len() as u64),
        products,
        observed_pylon_id: observed_pylon.id,
        account_link_id: account_link.id,
        user_id: account_link.user_id,
        link_state: account_link.state,
        link_method: account_link.method,
        proof_scheme: "nip98".to_string(),
        proof_event_id: proof.event_id.clone(),
        proof_payload_hash: proof.payload_hash.clone(),
    }
}

async fn complete_openagents_account_link(
    client: &reqwest::Client,
    base_url: &str,
    identity: &NostrIdentity,
    payload: &OpenAgentsPylonLinkCompletionRequest,
) -> Result<(
    OpenAgentsPylonLinkCompletionResponse,
    OpenAgentsAccountLinkProof,
)> {
    let url = openagents_account_link_url(base_url)?;
    let body = build_openagents_account_link_body(payload)?;
    let proof = build_openagents_account_link_proof(identity, &url, body.as_slice())?;
    let response = client
        .post(url.clone())
        .header(
            reqwest::header::AUTHORIZATION,
            proof.authorization_header.as_str(),
        )
        .header(reqwest::header::CONTENT_TYPE, "application/json")
        .body(body)
        .send()
        .await
        .with_context(|| format!("failed to post Pylon account link to {url}"))?;
    if !response.status().is_success() {
        let detail = response
            .text()
            .await
            .unwrap_or_else(|_| "failed to decode OpenAgents account-link error".to_string());
        bail!(
            "OpenAgents account link failed: {}",
            http_error_message(detail.as_str())
        );
    }
    response
        .json::<OpenAgentsPylonLinkCompletionResponse>()
        .await
        .with_context(|| format!("failed to decode OpenAgents account-link response from {url}"))
        .map(|response| (response, proof))
}

async fn run_account_link_command(
    config_path: &Path,
    base_url: &str,
    token: &str,
) -> Result<AccountLinkReport> {
    let config = ensure_local_setup(config_path)?;
    let identity = ensure_identity(config.identity_path.as_path())?;
    let status = load_status_or_detect(config_path).await?;
    let payload = build_openagents_account_link_request(&config, &identity, &status, token);
    let client = openagents_account_link_client()?;
    let (response, proof) =
        complete_openagents_account_link(&client, base_url, &identity, &payload).await?;
    Ok(build_account_link_report(base_url, response, &proof))
}

async fn try_live_status(config: &PylonConfig) -> Result<Option<ProviderStatusResponse>> {
    let client = admin_client()?;
    let url = format!("http://{}/v1/status", config.admin_listen_addr);
    let response = match client.get(url.as_str()).send().await {
        Ok(response) => response,
        Err(error) if is_local_control_unavailable(&error) => return Ok(None),
        Err(error) => return Err(anyhow!("failed to query pylon admin status: {error}")),
    };
    if !response.status().is_success() {
        let payload = response
            .json::<Value>()
            .await
            .unwrap_or_else(|_| json!({"error": "failed to decode provider status error"}));
        bail!(
            "provider admin status request failed: {}",
            api_error_detail(&payload)
        );
    }
    let status = response
        .json::<ProviderStatusResponse>()
        .await
        .context("failed to decode provider admin status response")?;
    Ok(Some(status))
}

async fn try_live_json<T: DeserializeOwned>(
    config: &PylonConfig,
    endpoint: &str,
) -> Result<Option<T>> {
    let client = admin_client()?;
    let url = format!("http://{}{}", config.admin_listen_addr, endpoint);
    let response = match client.get(url.as_str()).send().await {
        Ok(response) => response,
        Err(error) if is_local_control_unavailable(&error) => return Ok(None),
        Err(error) => {
            return Err(anyhow!(
                "failed to query pylon admin endpoint {}: {error}",
                endpoint
            ));
        }
    };
    if !response.status().is_success() {
        let payload = response
            .json::<Value>()
            .await
            .unwrap_or_else(|_| json!({"error": "failed to decode provider admin error"}));
        bail!(
            "provider admin endpoint {} failed: {}",
            endpoint,
            api_error_detail(&payload)
        );
    }
    let value = response
        .json::<T>()
        .await
        .with_context(|| format!("failed to decode pylon admin endpoint {}", endpoint))?;
    Ok(Some(value))
}

async fn try_live_training_post<T: DeserializeOwned>(
    config: &PylonConfig,
    endpoint: &str,
) -> Result<Option<T>> {
    let client = admin_client()?;
    let url = format!("http://{}{}", config.admin_listen_addr, endpoint);
    let response = match client.post(url.as_str()).send().await {
        Ok(response) => response,
        Err(error) if is_local_control_unavailable(&error) => return Ok(None),
        Err(error) => {
            return Err(anyhow!(
                "failed to call pylon training admin endpoint {}: {error}",
                endpoint
            ));
        }
    };
    if !response.status().is_success() {
        let payload = response
            .json::<Value>()
            .await
            .unwrap_or_else(|_| json!({"error": "failed to decode pylon training admin error"}));
        bail!(
            "pylon training admin endpoint {} failed: {}",
            endpoint,
            api_error_detail(&payload)
        );
    }
    let value = response.json::<T>().await.with_context(|| {
        format!(
            "failed to decode pylon training admin endpoint {}",
            endpoint
        )
    })?;
    Ok(Some(value))
}

async fn try_live_control(config: &PylonConfig, action: ProviderControlAction) -> Result<bool> {
    let client = admin_client()?;
    let endpoint = match action {
        ProviderControlAction::Online => "online",
        ProviderControlAction::Offline => "offline",
        ProviderControlAction::Pause => "pause",
        ProviderControlAction::Resume => "resume",
    };
    let url = format!("http://{}/v1/{endpoint}", config.admin_listen_addr);
    let response = match client.post(url.as_str()).send().await {
        Ok(response) => response,
        Err(error) if is_local_control_unavailable(&error) => return Ok(false),
        Err(error) => {
            return Err(anyhow!(
                "failed to call pylon admin {} endpoint: {error}",
                action.label()
            ));
        }
    };
    if !response.status().is_success() {
        let payload = response
            .json::<Value>()
            .await
            .unwrap_or_else(|_| json!({"error": "failed to decode provider control error"}));
        bail!(
            "provider admin {} failed: {}",
            action.label(),
            api_error_detail(&payload)
        );
    }
    response
        .json::<ProviderStatusResponse>()
        .await
        .with_context(|| format!("failed to decode {} control response", action.label()))?;
    Ok(true)
}

fn admin_client() -> Result<reqwest::Client> {
    reqwest::Client::builder()
        .timeout(Duration::from_secs(2))
        .build()
        .context("failed to build pylon admin client")
}

fn is_local_control_unavailable(error: &reqwest::Error) -> bool {
    error.is_connect() || error.is_timeout() || error.to_string().contains("Connection refused")
}

fn api_error_detail(payload: &Value) -> String {
    let code = payload.get("code").and_then(Value::as_str);
    let error = payload
        .get("error")
        .and_then(Value::as_str)
        .unwrap_or("unknown error");
    let current_state = payload.get("current_state").and_then(Value::as_str);
    match (code, current_state) {
        (Some(code), Some(current_state)) => {
            format!("{code}: {error} (current_state={current_state})")
        }
        (Some(code), None) => format!("{code}: {error}"),
        (None, _) => error.to_string(),
    }
}

async fn detect_availability(config: &PylonConfig) -> Result<ProviderAvailability> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(2))
        .build()
        .context("failed to build pylon health-check client")?;
    let local_gemma = detect_local_gemma(&client, config).await;
    let sandbox = detect_sandbox_supply(
        &ProviderSandboxDetectionConfig::default()
            .with_declared_profiles(config.declared_sandbox_profiles.clone()),
    );
    Ok(ProviderAvailability {
        local_gemma,
        apple_foundation_models: ProviderBackendHealth::default(),
        apple_adapter_hosting: ProviderAppleAdapterHostingAvailability::default(),
        adapter_training_contributor: detect_adapter_training_contributor(config),
        pooled_inference: ProviderPooledInferenceAvailability::default(),
        sandbox,
    })
}

fn detect_adapter_training_contributor(
    config: &PylonConfig,
) -> ProviderAdapterTrainingContributorAvailability {
    let host = load_cached_provider_host_telemetry(config.admin_db_path.as_path());
    let runtime_surface = inspect_psionic_train_runtime_surface().ok();
    let mut availability =
        derive_adapter_training_contributor_availability(&host, runtime_surface.as_ref());
    let _ = apply_training_reputation_gate_to_availability(config, &mut availability);
    availability
}

fn derive_adapter_training_contributor_availability(
    host: &ProviderHostTelemetrySnapshot,
    runtime_surface: Option<&PsionicTrainRuntimeSurface>,
) -> ProviderAdapterTrainingContributorAvailability {
    let Some(runtime_surface) = runtime_surface else {
        return ProviderAdapterTrainingContributorAvailability::default();
    };

    let coordinator_match_supported = host_has_training_network_posture(host);
    let authority_receipt_supported = host_has_training_checkpoint_posture(host);
    let has_cuda_backend = host_has_cuda_training_backend(host);
    let has_apple_backend =
        runtime_surface.supports_apple_windowed_training && host_has_apple_training_backend(host);
    let available_memory_gb =
        host_max_cuda_training_memory_gb(host).or_else(|| host_apple_training_memory_gb(host));
    let contributor_supported = (admitted_cuda_training_gpu(host).is_some()
        || admitted_apple_training_host(host, runtime_surface))
        && coordinator_match_supported
        && authority_receipt_supported;
    let mut environment_refs = Vec::new();
    if has_cuda_backend {
        environment_refs.push(PYLON_TRAINING_ENVIRONMENT_REF.to_string());
    }
    if has_apple_backend {
        environment_refs.push(PYLON_TRAINING_APPLE_ENVIRONMENT_REF.to_string());
    }
    let minimum_memory_gb = if admitted_cuda_training_gpu(host).is_some() || has_cuda_backend {
        Some(PYLON_TRAINING_MINIMUM_CUDA_MEMORY_GB)
    } else if has_apple_backend {
        Some(PYLON_TRAINING_MINIMUM_APPLE_MEMORY_GB)
    } else {
        None
    };

    ProviderAdapterTrainingContributorAvailability {
        contributor_supported,
        coordinator_match_supported,
        authority_receipt_supported,
        execution_backends: (has_cuda_backend || has_apple_backend)
            .then_some(ProviderAdapterTrainingExecutionBackend::OpenAdapterBackend)
            .into_iter()
            .collect(),
        adapter_families: vec![PYLON_TRAINING_ADAPTER_FAMILY.to_string()],
        adapter_formats: vec![PYLON_TRAINING_ADAPTER_FORMAT.to_string()],
        validator_policy_refs: vec![PYLON_TRAINING_VALIDATOR_POLICY_REF.to_string()],
        checkpoint_families: vec![PYLON_TRAINING_CHECKPOINT_FAMILY.to_string()],
        environment_refs,
        minimum_memory_gb,
        available_memory_gb,
        settlement_trigger: Some(ProviderAdapterTrainingSettlementTrigger::AcceptedSealedWindow),
    }
}

fn load_training_host_telemetry(config: &PylonConfig) -> ProviderHostTelemetrySnapshot {
    collect_provider_host_telemetry(config.training.run_root.as_path())
}

fn training_capability_backend_families(host: &ProviderHostTelemetrySnapshot) -> Vec<String> {
    let mut families = BTreeSet::new();
    if host_has_cuda_training_backend(host) {
        families.insert("cuda".to_string());
    }
    if host_has_apple_training_backend(host) {
        families.insert("metal".to_string());
    }
    families.into_iter().collect()
}

fn training_capability_backend_family_for_gpu(
    gpu: &ProviderHostGpuTelemetry,
) -> Option<&'static str> {
    if provider_gpu_is_cuda_training_backend(gpu) {
        Some("cuda")
    } else if provider_gpu_is_apple_training_backend(gpu) {
        Some("metal")
    } else {
        None
    }
}

fn training_capability_accelerator_inventory(
    host: &ProviderHostTelemetrySnapshot,
) -> Vec<ProviderTrainingAcceleratorInventoryEntry> {
    let mut grouped = BTreeMap::<(String, String, Option<String>, Option<u32>), u32>::new();
    for gpu in &host.gpus {
        let Some(backend_family) = training_capability_backend_family_for_gpu(gpu) else {
            continue;
        };
        let key = (
            backend_family.to_string(),
            gpu.model.clone(),
            gpu.vendor.clone().filter(|value| !value.trim().is_empty()),
            provider_gpu_memory_gb(gpu),
        );
        *grouped.entry(key).or_default() += 1;
    }
    grouped
        .into_iter()
        .map(
            |((backend_family, model, vendor, memory_per_accelerator_gb), accelerator_count)| {
                ProviderTrainingAcceleratorInventoryEntry {
                    backend_family,
                    model,
                    vendor,
                    accelerator_count,
                    memory_per_accelerator_gb,
                }
            },
        )
        .collect()
}

fn training_capability_available_memory_gb(
    host: &ProviderHostTelemetrySnapshot,
    availability: &ProviderAdapterTrainingContributorAvailability,
) -> Option<u32> {
    availability.available_memory_gb.or_else(|| {
        host.memory
            .as_ref()
            .map(|memory| bytes_to_gib_ceil(memory.total_bytes.max(memory.available_bytes)))
    })
}

fn training_capability_throughput_band(
    host: &ProviderHostTelemetrySnapshot,
    availability: &ProviderAdapterTrainingContributorAvailability,
) -> ProviderTrainingThroughputBand {
    let available_memory_gb = training_capability_available_memory_gb(host, availability);
    let cuda_accelerator_count = host
        .gpus
        .iter()
        .filter(|gpu| provider_gpu_is_cuda_training_backend(gpu))
        .count();
    match available_memory_gb {
        Some(memory_gb) if memory_gb >= 80 || cuda_accelerator_count >= 2 => {
            ProviderTrainingThroughputBand::Island
        }
        Some(memory_gb) if memory_gb >= 48 => ProviderTrainingThroughputBand::High,
        Some(memory_gb) if memory_gb >= 24 => ProviderTrainingThroughputBand::Medium,
        Some(_) => ProviderTrainingThroughputBand::Low,
        None => ProviderTrainingThroughputBand::Unknown,
    }
}

fn training_capability_replay_capability(
    config: &PylonConfig,
    availability: &ProviderAdapterTrainingContributorAvailability,
) -> ProviderTrainingReplayCapability {
    if config
        .training
        .role_claims
        .contains(&PylonTrainingRoleClaim::Validator)
    {
        ProviderTrainingReplayCapability::FullWindow
    } else if availability.authority_receipt_supported && availability.coordinator_match_supported {
        ProviderTrainingReplayCapability::ShortWindow
    } else {
        ProviderTrainingReplayCapability::None
    }
}

fn training_capability_lease_reliability(
    state: &PylonTrainingRuntimeState,
    host: &ProviderHostTelemetrySnapshot,
) -> ProviderTrainingLeaseReliabilityClass {
    let uptime_seconds = host.uptime_seconds.unwrap_or_default();
    let successful_closeouts = state.closeout_cache.len();
    let restart_count = state
        .active_runtime
        .as_ref()
        .map(|runtime| runtime.restart_count)
        .unwrap_or(0);
    if successful_closeouts >= 3 && uptime_seconds >= 86_400 && restart_count == 0 {
        ProviderTrainingLeaseReliabilityClass::Strong
    } else if successful_closeouts >= 1 || uptime_seconds >= 86_400 {
        ProviderTrainingLeaseReliabilityClass::Steady
    } else if uptime_seconds > 0 {
        ProviderTrainingLeaseReliabilityClass::Unproven
    } else {
        ProviderTrainingLeaseReliabilityClass::Unknown
    }
}

fn training_capability_artifact_upload_latency_class(
    state: &PylonTrainingRuntimeState,
) -> ProviderTrainingArtifactUploadLatencyClass {
    if state
        .publication_records
        .values()
        .any(|record| record.pending_retry || record.last_error.is_some())
    {
        ProviderTrainingArtifactUploadLatencyClass::Slow
    } else if !state.closeout_cache.is_empty() {
        ProviderTrainingArtifactUploadLatencyClass::Fast
    } else if !state.contribution_outcomes.is_empty() {
        ProviderTrainingArtifactUploadLatencyClass::Moderate
    } else {
        ProviderTrainingArtifactUploadLatencyClass::Unknown
    }
}

fn derive_training_capability_tier_profile(
    config: &PylonConfig,
    state: &PylonTrainingRuntimeState,
    host: &ProviderHostTelemetrySnapshot,
    availability: &ProviderAdapterTrainingContributorAvailability,
) -> ProviderTrainingCapabilityTierProfile {
    let backend_families = training_capability_backend_families(host);
    let accelerator_inventory = training_capability_accelerator_inventory(host);
    let available_memory_gb = training_capability_available_memory_gb(host, availability);
    let throughput_band = training_capability_throughput_band(host, availability);
    let lease_reliability = training_capability_lease_reliability(state, host);
    let replay_capability = training_capability_replay_capability(config, availability);
    let artifact_upload_latency_class = training_capability_artifact_upload_latency_class(state);
    let satisfies_memory_floor = match (available_memory_gb, availability.minimum_memory_gb) {
        (_, None) => true,
        (Some(available), Some(minimum)) => available >= minimum,
        (None, Some(_)) => false,
    };
    let trainer_ready = availability.contributor_supported && satisfies_memory_floor;
    let authority_capable = config
        .training
        .role_claims
        .contains(&PylonTrainingRoleClaim::Validator)
        && config
            .training
            .role_claims
            .contains(&PylonTrainingRoleClaim::RecoverySource)
        && throughput_band == ProviderTrainingThroughputBand::Island
        && matches!(
            lease_reliability,
            ProviderTrainingLeaseReliabilityClass::Steady
                | ProviderTrainingLeaseReliabilityClass::Strong
        );
    let tier = if authority_capable {
        ProviderTrainingCapabilityTier::Tier4Authority
    } else if trainer_ready && throughput_band == ProviderTrainingThroughputBand::Island {
        ProviderTrainingCapabilityTier::Tier3Island
    } else if trainer_ready {
        ProviderTrainingCapabilityTier::Tier2Trainer
    } else if replay_capability != ProviderTrainingReplayCapability::None {
        ProviderTrainingCapabilityTier::Tier1Validation
    } else {
        ProviderTrainingCapabilityTier::Tier0Presence
    };
    ProviderTrainingCapabilityTierProfile {
        tier,
        backend_families,
        accelerator_inventory,
        memory_floor_gb: availability.minimum_memory_gb,
        available_memory_gb,
        throughput_band,
        lease_reliability,
        replay_capability,
        artifact_upload_latency_class,
    }
}

fn host_has_training_network_posture(host: &ProviderHostTelemetrySnapshot) -> bool {
    !host.network_interfaces.is_empty()
}

fn host_has_training_checkpoint_posture(host: &ProviderHostTelemetrySnapshot) -> bool {
    primary_training_checkpoint_disk(host).is_some_and(|disk| disk.available_space_bytes > 0)
}

fn primary_training_checkpoint_disk(
    host: &ProviderHostTelemetrySnapshot,
) -> Option<&ProviderHostDiskTelemetry> {
    host.disks
        .iter()
        .find(|disk| disk.pylon_home_disk)
        .or_else(|| host.disks.first())
}

fn host_has_cuda_training_backend(host: &ProviderHostTelemetrySnapshot) -> bool {
    host.gpus.iter().any(provider_gpu_is_cuda_training_backend)
}

fn host_max_cuda_training_memory_gb(host: &ProviderHostTelemetrySnapshot) -> Option<u32> {
    host.gpus
        .iter()
        .filter(|gpu| provider_gpu_is_cuda_training_backend(gpu))
        .filter_map(provider_gpu_memory_gb)
        .max()
}

fn host_has_apple_training_backend(host: &ProviderHostTelemetrySnapshot) -> bool {
    host.cpu_arch
        .as_deref()
        .map(|arch| arch.eq_ignore_ascii_case("arm64") || arch.eq_ignore_ascii_case("aarch64"))
        .unwrap_or(false)
        && host.gpus.iter().any(provider_gpu_is_apple_training_backend)
}

fn host_apple_training_memory_gb(host: &ProviderHostTelemetrySnapshot) -> Option<u32> {
    host.memory
        .as_ref()
        .map(|memory| memory.total_bytes.max(memory.available_bytes))
        .filter(|bytes| *bytes > 0)
        .map(bytes_to_gib_ceil)
}

fn admitted_apple_training_host(
    host: &ProviderHostTelemetrySnapshot,
    runtime_surface: &PsionicTrainRuntimeSurface,
) -> bool {
    runtime_surface.supports_apple_windowed_training
        && host_has_apple_training_backend(host)
        && host_apple_training_memory_gb(host)
            .is_some_and(|memory_gb| memory_gb >= PYLON_TRAINING_MINIMUM_APPLE_MEMORY_GB)
}

fn admitted_cuda_training_gpu(
    host: &ProviderHostTelemetrySnapshot,
) -> Option<&ProviderHostGpuTelemetry> {
    host.gpus.iter().find(|gpu| {
        provider_gpu_is_cuda_training_backend(gpu)
            && provider_gpu_model_matches_admitted_cuda_family(gpu)
            && provider_gpu_memory_gb(gpu)
                .is_some_and(|memory_gb| memory_gb >= PYLON_TRAINING_MINIMUM_CUDA_MEMORY_GB)
    })
}

fn provider_gpu_is_cuda_training_backend(gpu: &ProviderHostGpuTelemetry) -> bool {
    let vendor = gpu
        .vendor
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    let model = gpu.model.to_ascii_lowercase();
    vendor.contains("nvidia") || model.contains("nvidia")
}

fn provider_gpu_is_apple_training_backend(gpu: &ProviderHostGpuTelemetry) -> bool {
    let vendor = gpu
        .vendor
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    let model = gpu.model.to_ascii_lowercase();
    vendor.contains("apple") || model.contains("apple")
}

fn provider_gpu_model_matches_admitted_cuda_family(gpu: &ProviderHostGpuTelemetry) -> bool {
    gpu.model
        .to_ascii_lowercase()
        .contains(PYLON_TRAINING_ADMITTED_CUDA_GPU_MODEL_FAMILY)
}

fn provider_gpu_memory_gb(gpu: &ProviderHostGpuTelemetry) -> Option<u32> {
    gpu.memory_total_bytes
        .or(gpu.memory_free_bytes)
        .map(bytes_to_gib_ceil)
}

fn bytes_to_gib_ceil(value: u64) -> u32 {
    let gib = value.saturating_add(BYTES_PER_GIB - 1) / BYTES_PER_GIB;
    u32::try_from(gib).unwrap_or(u32::MAX)
}

async fn detect_local_gemma(
    client: &reqwest::Client,
    config: &PylonConfig,
) -> ProviderBackendHealth {
    if !config.inventory_controls.local_gemma_inference_enabled
        && !config.inventory_controls.local_gemma_embeddings_enabled
    {
        return ProviderBackendHealth {
            last_action: Some("disabled by config".to_string()),
            ..ProviderBackendHealth::default()
        };
    }
    let url = format!(
        "{}/api/tags",
        config.local_gemma_base_url.trim_end_matches('/')
    );
    let response = match client.get(url.as_str()).send().await {
        Ok(response) => response,
        Err(error) => {
            return ProviderBackendHealth {
                reachable: false,
                ready: false,
                last_error: Some(format!(
                    "local Gemma runtime not reachable at {url}; start a local runtime serving /api/tags or update local_gemma_base_url ({error})"
                )),
                last_action: Some("health check failed".to_string()),
                ..ProviderBackendHealth::default()
            };
        }
    };
    let payload = match response.json::<Value>().await {
        Ok(payload) => payload,
        Err(error) => {
            return ProviderBackendHealth {
                reachable: true,
                ready: false,
                last_error: Some(format!(
                    "local Gemma runtime at {url} returned an invalid /api/tags payload; verify the runtime speaks the expected API or update local_gemma_base_url ({error})"
                )),
                last_action: Some("invalid local Gemma health payload".to_string()),
                ..ProviderBackendHealth::default()
            };
        }
    };
    let models = payload
        .get("models")
        .and_then(Value::as_array)
        .map(|models| {
            models
                .iter()
                .filter_map(|model| {
                    model
                        .get("name")
                        .and_then(Value::as_str)
                        .map(ToString::to_string)
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let gemma_models = models
        .into_iter()
        .filter(|model| is_gemma_model(model))
        .collect::<Vec<_>>();
    let provisional_health = ProviderBackendHealth {
        reachable: true,
        ready: false,
        configured_model: configured_local_gemma_model(config),
        ready_model: None,
        available_models: gemma_models.clone(),
        ..ProviderBackendHealth::default()
    };
    let ready_model = selected_local_gemma_runtime_model(config, &provisional_health);
    let preferred_model_missing = config.local_gemma_preferred_model.is_some()
        && ready_model.is_none()
        && !gemma_models.is_empty();
    let ready = ready_model.is_some();
    ProviderBackendHealth {
        reachable: true,
        ready,
        configured_model: configured_local_gemma_model(config)
            .or_else(|| gemma_models.first().cloned()),
        ready_model,
        available_models: gemma_models,
        last_error: if preferred_model_missing {
            Some(format!(
                "preferred local Gemma model `{}` is not loaded in the runtime at {url}. Available runtime models: {}",
                configured_local_gemma_model(config).unwrap_or_else(|| "unknown".to_string()),
                comma_or_none(&provisional_health.available_models)
            ))
        } else {
            (!ready).then(|| {
                format!(
                    "local Gemma runtime at {url} is reachable, but no Gemma 4 model is loaded. Downloaded GGUF files alone do not make supply eligible; start the runtime with a Gemma model or update local_gemma_base_url."
                )
            })
        },
        last_action: Some(if ready {
            "health check ready".to_string()
        } else if preferred_model_missing {
            "preferred gemma model missing".to_string()
        } else {
            "gemma models not loaded".to_string()
        }),
        availability_message: Some(if ready {
            "gemma_ready".to_string()
        } else if preferred_model_missing {
            "gemma_preferred_missing".to_string()
        } else {
            "gemma_missing".to_string()
        }),
        ..ProviderBackendHealth::default()
    }
}

fn apply_config_set(config: &mut PylonConfig, key: &str, value: &str) -> Result<()> {
    let mut next = config.clone();
    match key {
        "node_label" => next.node_label = value.to_string(),
        "payout_destination" => {
            next.payout_destination = if value.trim().is_empty() {
                None
            } else {
                Some(value.to_string())
            };
        }
        "admin_listen_addr" => next.admin_listen_addr = value.to_string(),
        "nexus_control_base_url" => {
            let trimmed = value.trim();
            if trimmed.is_empty() {
                bail!("nexus_control_base_url must not be empty");
            }
            next.nexus_control_base_url = trimmed.to_string();
        }
        "relay_connect_timeout_seconds" => {
            next.relay_connect_timeout_seconds = value
                .parse::<u64>()
                .with_context(|| format!("invalid relay_connect_timeout_seconds: {value}"))?;
        }
        "relay_auth_enabled" => {
            next.relay_auth_enabled = parse_bool(value)?;
        }
        "wallet_network" => next.wallet_network = value.trim().to_string(),
        "wallet_api_key_env" => {
            next.wallet_api_key_env = if value.trim().is_empty() {
                None
            } else {
                Some(value.trim().to_string())
            };
        }
        "buyer_auto_pay_enabled" => {
            next.buyer_auto_pay_enabled = parse_bool(value)?;
        }
        "wallet_storage_dir" => next.wallet_storage_dir = PathBuf::from(value.trim()),
        "local_gemma_base_url" | "ollama_base_url" => {
            next.local_gemma_base_url = value.to_string();
        }
        "local_gemma_preferred_model" => {
            next.local_gemma_preferred_model = if value.trim().is_empty() {
                None
            } else {
                Some(canonical_local_gemma_model_id(value))
            };
        }
        "backend.local_gemma_inference_enabled"
        | "backend.gpt_oss_inference_enabled"
        | "backend.ollama_inference_enabled" => {
            next.inventory_controls.local_gemma_inference_enabled = parse_bool(value)?;
        }
        "backend.local_gemma_embeddings_enabled"
        | "backend.gpt_oss_embeddings_enabled"
        | "backend.ollama_embeddings_enabled" => {
            next.inventory_controls.local_gemma_embeddings_enabled = parse_bool(value)?;
        }
        "backend.sandbox_container_exec_enabled" => {
            next.inventory_controls.sandbox_container_exec_enabled = parse_bool(value)?;
        }
        "backend.sandbox_python_exec_enabled" => {
            next.inventory_controls.sandbox_python_exec_enabled = parse_bool(value)?;
        }
        "backend.sandbox_node_exec_enabled" => {
            next.inventory_controls.sandbox_node_exec_enabled = parse_bool(value)?;
        }
        "backend.sandbox_posix_exec_enabled" => {
            next.inventory_controls.sandbox_posix_exec_enabled = parse_bool(value)?;
        }
        "training.allowed_networks" => {
            next.training.allowed_networks = parse_csv_list(value);
        }
        "training.role_claims" => {
            next.training.role_claims = parse_training_role_claim_list(value)?;
        }
        "training.run_root" => {
            next.training.run_root = PathBuf::from(value.trim());
        }
        "training.artifact_credential_source_names" => {
            next.training.artifact_credential_source_names = parse_csv_list(value);
        }
        "training.checkpoint_serve_addr" => {
            next.training.checkpoint_serve_addr = value.trim().to_string();
        }
        "training.nexus_authority_base_url" => {
            next.training.nexus_authority_base_url = value.trim().to_string();
        }
        "training.relay_urls" => {
            next.training.relay_urls = parse_csv_list(value);
        }
        "training.validator_enabled" => {
            next.training.validator_enabled = parse_bool(value)?;
        }
        "training.disk_quota_gb" => {
            next.training.disk_quota_gb = value
                .trim()
                .parse::<u64>()
                .with_context(|| format!("invalid training.disk_quota_gb: {value}"))?;
        }
        "training.retention_limit_gb" => {
            next.training.retention_limit_gb = value
                .trim()
                .parse::<u64>()
                .with_context(|| format!("invalid training.retention_limit_gb: {value}"))?;
        }
        other => bail!("unsupported config key: {other}"),
    }
    validate_pylon_config(&next)?;
    *config = next;
    Ok(())
}

fn parse_bool(value: &str) -> Result<bool> {
    match value.trim() {
        "true" | "1" | "yes" | "on" => Ok(true),
        "false" | "0" | "no" | "off" => Ok(false),
        other => bail!("invalid boolean value: {other}"),
    }
}

fn parse_csv_list(value: &str) -> Vec<String> {
    value
        .split(',')
        .map(str::trim)
        .filter(|entry| !entry.is_empty())
        .map(ToString::to_string)
        .collect()
}

fn parse_training_role_claim_list(value: &str) -> Result<Vec<PylonTrainingRoleClaim>> {
    parse_csv_list(value)
        .into_iter()
        .map(|value| match value.as_str() {
            "worker" => Ok(PylonTrainingRoleClaim::Worker),
            "validator" => Ok(PylonTrainingRoleClaim::Validator),
            "recovery_source" => Ok(PylonTrainingRoleClaim::RecoverySource),
            other => bail!("unsupported training role claim: {other}"),
        })
        .collect()
}

fn now_epoch_ms() -> i64 {
    match std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH) {
        Ok(duration) => i64::try_from(duration.as_millis()).unwrap_or(i64::MAX),
        Err(_) => 0,
    }
}

fn random_token() -> String {
    hex::encode(rand::random::<[u8; 16]>())
}

